import React, { useState, useEffect } from 'react';
import StatCard from '../components/StatCard';

const BookingsManagement = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [updatingStatus, setUpdatingStatus] = useState(null);

  // Mock bookings data for comprehensive display
  const mockBookings = [
    { id: 1, booking_id: 'BK-1045', customer_name: 'Rahul ', customer_email: 'rahul@email.com', bike_name: 'Royal Enfield Classic 350', total_amount: 4500, status: 'confirmed', pickup_date: '2026-02-25', return_date: '2026-02-28', created_at: '2026-02-24T10:30:00' },
    { id: 2, booking_id: 'BK-1044', customer_name: 'Goutham', customer_email: 'goutham@email.com', bike_name: 'NS 200', total_amount: 3600, status: 'active', pickup_date: '2026-02-23', return_date: '2026-02-26', created_at: '2026-02-23T14:15:00' },
    { id: 3, booking_id: 'BK-1043', customer_name: 'Amit Patel', customer_email: 'amit@email.com', bike_name: 'GT 650', total_amount: 7500, status: 'pending', pickup_date: '2026-02-26', return_date: '2026-03-01', created_at: '2026-02-23T09:00:00' },
    { id: 4, booking_id: 'BK-1042', customer_name: 'Sneha Reddy', customer_email: 'sneha@email.com', bike_name: 'DUKE 200', total_amount: 3800, status: 'active', pickup_date: '2026-02-22', return_date: '2026-02-25', created_at: '2026-02-22T11:00:00' },
    { id: 5, booking_id: 'BK-1041', customer_name: 'Vikram Singh', customer_email: 'vikram@email.com', bike_name: 'MT 15', total_amount: 3200, status: 'completed', pickup_date: '2026-02-20', return_date: '2026-02-22', created_at: '2026-02-20T08:30:00' },
    { id: 6, booking_id: 'BK-1040', customer_name: 'Neha Gupta', customer_email: 'neha@email.com', bike_name: 'INTERCEPTOR 650', total_amount: 6300, status: 'completed', pickup_date: '2026-02-18', return_date: '2026-02-21', created_at: '2026-02-18T16:00:00' },
    { id: 7, booking_id: 'BK-1039', customer_name: 'Arjun Nair', customer_email: 'arjun@email.com', bike_name: 'NS 200', total_amount: 5400, status: 'cancelled', pickup_date: '2026-02-19', return_date: '2026-02-22', created_at: '2026-02-19T12:00:00' },
    { id: 8, booking_id: 'BK-1038', customer_name: 'Kavitha Menon', customer_email: 'kavitha@email.com', bike_name: 'Royal Enfield Classic 350', total_amount: 4500, status: 'completed', pickup_date: '2026-02-15', return_date: '2026-02-18', created_at: '2026-02-15T10:00:00' },
  ];

  useEffect(() => {
    fetchBookings();
  }, []);

  const fetchBookings = async () => {
    try {
      const response = await fetch('http://localhost:5002/api/bookings');
      const result = await response.json();
      if (result.success && result.data.length > 0) {
        setBookings(result.data);
      } else {
        setBookings(mockBookings);
      }
    } catch (error) {
      console.log('Using mock data');
      setBookings(mockBookings);
    } finally {
      setLoading(false);
    }
  };

  const handleStatusUpdate = async (bookingId, newStatus) => {
    setUpdatingStatus(bookingId);
    try {
      const response = await fetch(`http://localhost:5002/api/bookings/${bookingId}/status`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: newStatus }),
      });
      const result = await response.json();
      if (result.success) {
        setBookings(prev => prev.map(b => b.id === bookingId ? { ...b, status: newStatus } : b));
      }
    } catch (error) {
      setBookings(prev => prev.map(b => b.id === bookingId ? { ...b, status: newStatus } : b));
    } finally {
      setUpdatingStatus(null);
    }
  };

  const tabs = [
    { key: 'all', label: 'All' },
    { key: 'pending', label: 'Pending' },
    { key: 'confirmed', label: 'Confirmed' },
    { key: 'active', label: 'Active' },
    { key: 'completed', label: 'Completed' },
    { key: 'cancelled', label: 'Cancelled' },
  ];

  const filteredBookings = bookings.filter(b => {
    const matchesTab = activeTab === 'all' || b.status === activeTab;
    const matchesSearch = (b.customer_name || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
      (b.booking_id || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
      (b.bike_name || '').toLowerCase().includes(searchTerm.toLowerCase());
    return matchesTab && matchesSearch;
  });

  const stats = {
    total: bookings.length,
    pending: bookings.filter(b => b.status === 'pending').length,
    active: bookings.filter(b => b.status === 'active').length,
    completed: bookings.filter(b => b.status === 'completed').length,
    revenue: bookings.reduce((sum, b) => sum + (parseFloat(b.total_amount) || 0), 0),
  };

  const getStatusBadge = (status) => {
    const map = { pending: 'warning', confirmed: 'info', active: 'success', completed: 'neutral', cancelled: 'danger' };
    return map[status] || 'neutral';
  };

  const statusActions = {
    pending: ['confirmed', 'cancelled'],
    confirmed: ['active', 'cancelled'],
    active: ['completed'],
  };

  return (
    <div>
      {/* Stats Row */}
      <div className="stats-grid">
        <StatCard icon="📋" label="Total Bookings" value={stats.total} color="blue" />
        <StatCard icon="⏳" label="Pending" value={stats.pending} color="orange" trend={stats.pending > 0 ? 'up' : undefined} trendValue={stats.pending > 0 ? 'Action needed' : undefined} />
        <StatCard icon="🚀" label="Active Rides" value={stats.active} color="green" />
        <StatCard icon="✅" label="Completed" value={stats.completed} color="purple" />
        <StatCard icon="💰" label="Total Revenue" value={`₹${stats.revenue.toLocaleString()}`} color="blue" trend="up" trendValue="12%" />
      </div>

      {/* Toolbar */}
      <div className="toolbar">
        <div className="toolbar-search">
          <span className="toolbar-search-icon">🔍</span>
          <input
            type="text"
            placeholder="Search bookings..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="filter-tabs">
          {tabs.map(tab => (
            <button
              key={tab.key}
              className={`filter-tab ${activeTab === tab.key ? 'active' : ''}`}
              onClick={() => setActiveTab(tab.key)}
            >
              {tab.label}
            </button>
          ))}
        </div>

        <button className="btn btn-secondary btn-sm" style={{ marginLeft: 'auto' }}>📥 Export</button>
      </div>

      {/* Bookings Table */}
      {loading ? (
        <div className="loading"><div className="spinner"></div></div>
      ) : filteredBookings.length === 0 ? (
        <div className="card">
          <div className="empty-state">
            <div className="empty-state-icon">📋</div>
            <h3>No Bookings Found</h3>
            <p>No bookings match your current filter criteria</p>
          </div>
        </div>
      ) : (
        <div className="card">
          <div className="data-table-container">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Booking ID</th>
                  <th>Customer</th>
                  <th>Bike</th>
                  <th>Dates</th>
                  <th>Amount</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredBookings.map(booking => (
                  <tr key={booking.id}>
                    <td className="table-cell-main">{booking.booking_id || `BK-${booking.id}`}</td>
                    <td>
                      <div>
                        <div className="table-cell-main">{booking.customer_name}</div>
                        <div className="table-cell-sub">{booking.customer_email}</div>
                      </div>
                    </td>
                    <td>{booking.bike_name || `Bike #${booking.bike_id}`}</td>
                    <td>
                      <div>
                        <div className="table-cell-sub">
                          {booking.pickup_date ? new Date(booking.pickup_date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }) : '—'}
                          {' → '}
                          {booking.return_date ? new Date(booking.return_date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }) : '—'}
                        </div>
                      </div>
                    </td>
                    <td className="table-cell-main">₹{parseFloat(booking.total_amount).toLocaleString()}</td>
                    <td>
                      <span className={`badge badge--${getStatusBadge(booking.status)}`}>
                        <span className="badge-dot"></span>
                        {booking.status}
                      </span>
                    </td>
                    <td>
                      <div style={{ display: 'flex', gap: '0.35rem' }}>
                        {(statusActions[booking.status] || []).map(action => (
                          <button
                            key={action}
                            className={`btn btn-sm ${action === 'cancelled' ? 'btn-ghost' : 'btn-secondary'}`}
                            onClick={() => handleStatusUpdate(booking.id, action)}
                            disabled={updatingStatus === booking.id}
                            style={{ textTransform: 'capitalize' }}
                          >
                            {action === 'cancelled' ? '✕' : action}
                          </button>
                        ))}
                        {!statusActions[booking.status] && (
                          <span className="table-cell-sub">—</span>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="card-footer" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
              Showing {filteredBookings.length} of {bookings.length} bookings
            </span>
          </div>
        </div>
      )}
    </div>
  );
};

export default BookingsManagement;
